const _e=JSON.parse(JSON.stringify($input.item.json._e));const aStr=JSON.stringify(_e.alert||{});
const priv=[/^10\./,/^172\.(1[6-9]|2\d|3[01])\./,/^192\.168\./,/^127\./,/^169\.254\./,/^0\./,/^255\./];
const isPriv=ip=>priv.some(r=>r.test(ip));
const trusted=['microsoft.com','windows.com','windowsupdate.com','google.com','googleapis.com','amazonaws.com','cloudflare.com','digicert.com','verisign.com','akamai.com'];
const ipRx=/\b(?:(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\.){3}(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\b/g;
const domRx=/(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+(?:com|net|org|io|gov|edu|co|ru|cn|xyz|top|club|online|site|tech|cloud|app|dev|ai|me|cc|biz|info|tk|ml|pw)/g;
const ips=new Set(),domains=new Set(),urls=new Set(),hashes=new Set();
if(_e._seeds?.src_ip&&!isPriv(_e._seeds.src_ip))ips.add(_e._seeds.src_ip);
(aStr.match(ipRx)||[]).forEach(ip=>{if(!isPriv(ip))ips.add(ip);});
if(_e._seeds?.domain)domains.add(_e._seeds.domain.toLowerCase());
(aStr.match(domRx)||[]).forEach(d=>domains.add(d.toLowerCase()));
if(_e._seeds?.url)urls.add(_e._seeds.url);
((_e.alert?.full_log||'').match(/https?:\/\/[^\s'"<>\]\[)]+/g)||[]).forEach(u=>urls.add(u));
if(_e._seeds?.hash)hashes.add(_e._seeds.hash.toLowerCase());
(aStr.match(/\b[a-fA-F0-9]{64}\b/g)||[]).forEach(h=>hashes.add(h.toLowerCase()));
_e.iocs={ips:[...ips].slice(0,5),domains:[...domains].filter(d=>!trusted.some(t=>d.endsWith(t))).slice(0,5),urls:[...urls].slice(0,5),hashes:[...hashes].slice(0,5)};
if(!_e.alert_id)throw new Error('INTEGRITY: alert_id missing after IOC extraction');
return [{json:{_e}}];

// ═══════════════════════════════════════════════════════════════
// SOC ALERT SUMMARIZER v5
// Changes from v4:
//   → Added C — Alert Dedup Gate burst/dedup intel extraction
//   → Added DEDUP/BURST section to email report
//   → Added burst banner line to Telegram message
//   → Added unique source IPs list to Telegram on burst
//   → Telegram character budget kept: +200–300 chars max on burst
//   → Zero changes to any existing v4 logic or output structure
// ═══════════════════════════════════════════════════════════════
const _e    = $input.item.json._e;
const AUDIT = $input.item.json.AUDIT;
const ai    = _e.ai_analysis || {};
const ti    = _e.threat_intel || {};
const host  = _e.host || {};
const alert = _e.alert || {};
const iocs  = _e.iocs || {};
const net   = _e.network || {};
const tl = AUDIT.timeline || _e.timeline || {};

// ── Emoji Maps ──────────────────────────────────────────────────
const sevEmoji  = { critical:'🚨', high:'🔴', medium:'🟡', low:'🔵', informational:'⚪' };
const verdEmoji = { TRUE_POSITIVE:'✅ TRUE POSITIVE', FALSE_POSITIVE:'❌ FALSE POSITIVE', BENIGN:'🟢 BENIGN', NEEDS_INVESTIGATION:'⚠️ NEEDS INVESTIGATION' };
const confEmoji = { HIGH:'🔒 HIGH', MEDIUM:'🔶 MEDIUM', LOW:'🔓 LOW' };
const tiEmoji   = { malicious:'🔴 MALICIOUS', suspicious:'🟠 SUSPICIOUS', low_risk:'🟡 LOW RISK', clean:'🟢 CLEAN', unknown:'⚪ UNKNOWN' };

const se = sevEmoji[_e.severity_tier]   || '⚪';
const ve = verdEmoji[ai.alert_verdict]  || ai.alert_verdict || 'N/A';
const ce = confEmoji[ai.confidence]     || ai.confidence    || 'N/A';
const te = tiEmoji[ti.summary?.verdict] || ti.summary?.verdict || 'N/A';

// ── Helpers ─────────────────────────────────────────────────────
const safe  = (v, fallback='N/A') => (v !== undefined && v !== null && v !== '') ? v : fallback;
const arr   = (v) => Array.isArray(v) && v.length > 0 ? v : null;
const trunc = (s, n) => s && s.length > n ? s.slice(0, n) + '...' : (s || 'N/A');

// ── Success Detection ───────────────────────────────────────────
const successDetected =
  ai.analysis?.toLowerCase().includes('successful') ||
  alert.full_log?.toLowerCase().includes('accepted password');

// ── Duration Calc ───────────────────────────────────────────────
const totalSec = tl.total_ms ? Math.round(tl.total_ms / 1000) : null;
const duration = totalSec ? `${Math.floor(totalSec/60)}m ${totalSec%60}s` : 'N/A';

// ── Engine Icon Map — updated for Aggregator v3 statuses ────────
const engineIcon = (v) => {
  if (!v) return '➖';
  if (v === 'ok')                         return '✅';
  if (v.startsWith('ok('))               return '✅';
  if (v === 'ok_no_verdict')             return '➖';
  if (v === 'ok_not_found')             return '🔍';
  if (v === 'ok_found')                 return '🚨';
  if (v === 'error')                    return '❌';
  if (v.includes('failed'))            return '❌';
  if (v === 'rate_limited_429')        return '⚠️';
  if (v.startsWith('skipped'))         return '⏭️';
  if (v === 'illegal_hash_format')     return '⚠️';
  if (v === 'no_response')             return '🔘';
  return '➖';
};

// ── TI Engine Summary ───────────────────────────────────────────
const engines = ti.engines || {};
const engineLines = Object.entries(engines).map(([k, v]) => {
  return `    ${engineIcon(v)} ${k}: ${v}`;
}).join('\n');

// ── Engine Health Stats ─────────────────────────────────────────
const engOk      = safe(ti.summary?.engines_ok, 0);
const engErr     = safe(ti.summary?.engines_error, 0);
const engSkipped = safe(ti.summary?.engines_skipped, 0);
const engTotal   = safe(ti.summary?.engines_total, 0);
const engHealth  = `✅ OK: ${engOk} | ❌ Error: ${engErr} | ⏭️ Skipped: ${engSkipped} | Total: ${engTotal}`;
const tgEngHealth = `Engines: ✅${engOk} ❌${engErr} ⏭️${engSkipped} / ${engTotal}`;

// ── IOC Lines ───────────────────────────────────────────────────
const iocLines = [
  arr(ai.ioc_analysis?.malicious_ips)     ? `    🔴 Malicious IPs    : ${ai.ioc_analysis.malicious_ips.join(', ')}` : null,
  arr(ai.ioc_analysis?.malicious_domains) ? `    🔴 Malicious Domains: ${ai.ioc_analysis.malicious_domains.join(', ')}` : null,
  arr(ai.ioc_analysis?.malicious_hashes)  ? `    🔴 Malicious Hashes : ${ai.ioc_analysis.malicious_hashes.join(', ')}` : null,
  arr(ai.ioc_analysis?.suspicious_urls)   ? `    🟠 Suspicious URLs  : ${ai.ioc_analysis.suspicious_urls.join(', ')}` : null,
  `    🧾 IOC Verdict       : ${safe(ai.ioc_analysis?.ioc_verdict).toUpperCase()}`
].filter(Boolean).join('\n');

// ── TI Reputation Detail ─────────────────────────────────────────
const repLines = [];

if (ti.ip_rep?.abuseipdb) {
  const a = ti.ip_rep.abuseipdb;
  repLines.push(`    AbuseIPDB  : Score=${safe(a.score)}% | ISP=${safe(a.isp)} | Country=${safe(a.country)} | Reports=${safe(a.reports)} | TOR=${safe(a.is_tor)}`);
  if (a.hostnames?.length > 0) repLines.push(`               Hostnames: ${a.hostnames.join(', ')}`);
  if (a.note) repLines.push(`               ⚠️ Note: ${a.note}`);
}
if (ti.ip_rep?.virustotal) {
  const v = ti.ip_rep.virustotal;
  repLines.push(`    VT IP      : Malicious=${safe(v.malicious)} | Suspicious=${safe(v.suspicious)} | ASN=${safe(v.asn_owner)} | Country=${safe(v.country)}`);
}
if (ti.domain_rep?.virustotal) {
  const v = ti.domain_rep.virustotal;
  repLines.push(`    VT Domain  : Malicious=${safe(v.malicious)} | Suspicious=${safe(v.suspicious)} | Domain=${safe(v.domain)}`);
}
if (ti.domain_rep?.otx) {
  const o = ti.domain_rep.otx;
  repLines.push(`    OTX Domain : Pulses=${safe(o.pulse_count)} | Indicator=${safe(o.indicator)} | Families=${(o.malware_families||[]).join(',')||'None'}`);
  if (arr(o.pulses)) repLines.push(`               Campaigns: ${o.pulses.map(p=>p.name).slice(0,3).join(' | ')}`);
}
if (ti.url_rep?.otx) {
  const o = ti.url_rep.otx;
  repLines.push(`    OTX URL    : Pulses=${safe(o.pulse_count)} | Type=${safe(o.type)} | Indicator=${trunc(safe(o.indicator),60)}`);
  if (arr(o.pulses)) repLines.push(`               Campaigns: ${o.pulses.map(p=>p.name).slice(0,3).join(' | ')}`);
  if (arr(o.malware_families)) repLines.push(`               Families: ${o.malware_families.join(', ')}`);
}
if (ti.hash_rep?.virustotal) {
  const v = ti.hash_rep.virustotal;
  repLines.push(`    VT Hash    : Malicious=${safe(v.malicious)} | Suspicious=${safe(v.suspicious)} | Name=${safe(v.name)} | Type=${safe(v.type)}`);
}
if (ti.hash_rep?.hybrid) {
  const h = ti.hash_rep.hybrid;
  repLines.push(`    Hybrid     : Verdict=${safe(h.verdict)} | Multiscan=${safe(h.multiscan_result)}% | CrowdStrike=${safe(h.crowdstrike_ml)} | Family=${safe(h.family)}`);
  if (h.metadefender) repLines.push(`               MetaDefender: ${h.metadefender}`);
  if (h.hash_note)    repLines.push(`               ⚠️ Hash Mismatch: ${h.hash_note}`);
}

// ── Actions ─────────────────────────────────────────────────────
const actionLines   = (arr(ai.recommended_actions)||[]).map(a=>`    ${a}`).join('\n');
const timelineLines = (arr(ai.investigation_timeline)||[]).map(s=>`    ${s}`).join('\n');
const improvLines   = arr(ai.detection_improvements) ? ai.detection_improvements.map(d=>`    • ${d}`).join('\n') : '    • None provided';

// ── MITRE ───────────────────────────────────────────────────────
const mitre    = ai.mitre_attack || {};
const mitreStr = [
  arr(mitre.tactics)        ? `Tactics    : ${mitre.tactics.join(', ')}` : null,
  arr(mitre.techniques)     ? `Techniques : ${mitre.techniques.join(', ')}` : null,
  arr(mitre.sub_techniques) ? `Sub-Tech   : ${mitre.sub_techniques.join(', ')}` : null,
].filter(Boolean).map(l=>`    ${l}`).join('\n');

// ── Compliance ──────────────────────────────────────────────────
const comp = alert.compliance || {};
const compLines = Object.entries(comp)
  .filter(([, v]) => Array.isArray(v) && v.length > 0)
  .map(([k, v]) => `    ${k.toUpperCase()}: ${v.join(', ')}`)
  .join('\n');
const tgComp = Object.entries(comp)
  .filter(([, v]) => Array.isArray(v) && v.length > 0)
  .map(([k, v]) => `${k.toUpperCase()}:${v.join(',')}`)
  .join(' | ') || 'N/A';

// ── Vulnerability ───────────────────────────────────────────────
const vuln    = alert.vulnerability || {};
const vulnStr = vuln.cve ? `${vuln.cve} | ${safe(vuln.severity)} | ${safe(vuln.title)} | Package: ${safe(vuln.pkg)} v${safe(vuln.version)}` : 'None';
const tgVuln  = vuln.cve ? `${vuln.cve} (${safe(vuln.severity)}) | ${safe(vuln.pkg)} v${safe(vuln.version)}` : 'None';

// ── Syscheck ────────────────────────────────────────────────────
const sys    = alert.syscheck || {};
const sysStr = sys.path ? `Path: ${sys.path} | Event: ${sys.event} | By: ${safe(sys.modified_by)} | Process: ${safe(sys.process)}` : 'N/A';
const tgSys  = sys.path ? `${sys.path} | ${sys.event} | by ${safe(sys.modified_by)}` : 'N/A';

// ════════════════════════════════════════════════════════════════
// NEW v5 — DEDUP / BURST DETECTION EXTRACTION
// Reads _dedup object written by C — Alert Dedup Gate
// ════════════════════════════════════════════════════════════════
const dedup       = _e._dedup || {};
const isBurst     = dedup.is_burst_flush  ?? false;
const isFirst     = dedup.is_first        ?? true;
const attackPat   = dedup.attack_pattern  || null;
const burstIPs    = dedup.unique_src_ips  || [];
const attemptCnt  = dedup.attempt_count   || 1;
const burstRate   = dedup.rate_per_min    || null;
const burstDur    = dedup.burst_duration_s|| null;
const flushTrig   = dedup.flush_trigger   || null;

// ── Dedup status label ──
const dedupStatus = isBurst
  ? `⚡ BURST FLUSH — ${attackPat || 'REPEATED_ALERT'}`
  : isFirst
    ? `✅ FIRST OCCURRENCE`
    : `ℹ️ SINGLE EVENT`;

// ── Email: full dedup section lines ──
// Shown always — burst rows only rendered when isBurst=true
const dedupEmailSection = [
  ``,
  `${'─'.repeat(60)}`,
  `🔁 DEDUP / BURST DETECTION`,
  `${'─'.repeat(60)}`,
  `  Status         : ${dedupStatus}`,
  isBurst ? `  Attack Pattern  : ${attackPat}` : null,
  isBurst ? `  Total Attempts  : ${attemptCnt}` : null,
  isBurst ? `  Rate            : ~${burstRate} attempts/min` : null,
  isBurst ? `  Burst Duration  : ${burstDur}s` : null,
  isBurst ? `  Unique Sources  : ${burstIPs.length} IP(s)` : null,
  isBurst && burstIPs.length > 0
    ? `  Source IPs      :\n${burstIPs.map(ip=>`    • ${ip}`).join('\n')}`
    : null,
  isBurst ? `  Flush Trigger   : ${flushTrig === 'threshold' ? '🔢 Threshold hit' : '⏱️ Time interval'}` : null,
  ``,
].filter(l => l !== null);

// ── Telegram: burst banner (only if burst — keeps char budget tight) ──
// Format: 2 lines max, ~200–250 chars total added
const tgDedupLines = isBurst
  ? [
      ``,
      `⚡ <b>BURST DETECTED</b> | ${attackPat} | ${attemptCnt} attempts | ${burstIPs.length} src IPs | ~${burstRate}/min | ${burstDur}s`,
      burstIPs.length > 0
        ? `🌐 Sources: <code>${burstIPs.slice(0,4).join(', ')}${burstIPs.length > 4 ? ` +${burstIPs.length-4} more` : ''}</code>`
        : null,
    ].filter(l => l !== null)
  : [];  // no lines added for first-occurrence or single events — keeps Telegram clean

// ════════════════════════════════════════════════════════════════
// FULL EMAIL SUMMARY
// ════════════════════════════════════════════════════════════════
const lines = [
  `${se} SOC ALERT TRIAGE REPORT`,
  `${'═'.repeat(60)}`,
  ``,
  `📋 ALERT IDENTIFICATION`,
  `  Alert ID    : ${safe(_e.alert_id)}`,
  `  Generated   : ${safe(alert.timestamp)}`,
  `  Pipeline    : ${safe(_e.pipeline).toUpperCase()}`,
  `  Rule ID     : ${safe(alert.rule_id)}`,
  `  Rule Desc   : ${safe(alert.rule_desc)}`,
  `  Rule Level  : ${safe(alert.rule_level)}`,
  `  Groups      : ${(alert.rule_groups||[]).join(', ')||'N/A'}`,
  `  Fired Times : ${safe(alert.fired_times)} attempts`,
  `  Log Source  : ${safe(host.location)}`,
  ``,
  `🖥️ HOST CONTEXT`,
  `  Agent Name  : ${safe(host.agent_name)}`,
  `  Agent IP    : ${safe(host.agent_ip)}`,
  `  Agent ID    : ${safe(host.agent_id)}`,
  `  OS          : ${safe(host.os)}`,
  `  Environment : ${safe(host.labels?.environment)}`,
  `  Criticality : ${safe(host.labels?.criticality)}`,
  `  Geo         : ${safe(host.geo?.city)}, ${safe(host.geo?.country)}`,
  ``,
  `🌐 NETWORK CONTEXT`,
  `  Src IP      : ${safe(net.src_ip)}`,
  `  Src Port    : ${safe(net.src_port)}`,
  `  Dst User    : ${safe(net.dst_user)}`,
  `  Src Country : ${safe(net.src_country)}, ${safe(net.src_city)}`,
  `  Protocol    : ${safe(net.protocol)}`,

  // ── v5 INSERT: Dedup/Burst section after Network Context ──
  ...dedupEmailSection,

  `📄 RAW LOG`,
  `  ${safe(alert.full_log).slice(0,300)}`,
  alert.cmdline ? `  Cmdline: ${alert.cmdline}` : null,
  ``,
  `${'─'.repeat(60)}`,
  `🤖 AI ANALYSIS — ${safe(AUDIT?.ai_model)} via ${safe(AUDIT?.ai_provider)}`,
  `${'─'.repeat(60)}`,
  ``,
  `🎯 VERDICT SUMMARY`,
  `  Verdict     : ${ve}`,
  `  Confidence  : ${ce}`,
  `  Severity    : ${safe(ai.incident_severity)}`,
  `  Risk Score  : ${safe(ai.risk_score)}/100`,
  `  Attack Type : ${safe(ai.attack_type)}`,
  `  TI Verdict  : ${te} (Score: ${safe(ti.summary?.score)})`,
  ``,
  `📝 ANALYST BRIEFING`,
  `  ${safe(ai.analysis)}`,
  ``,
  `🧬 MITRE ATT&CK`,
  mitreStr || '  N/A',
  ``,
  `${'─'.repeat(60)}`,
  `🔍 IOC ANALYSIS`,
  `${'─'.repeat(60)}`,
  iocLines,
  ``,
  `  📦 Raw IOCs`,
  arr(iocs.ips)     ? `    IPs     : ${iocs.ips.join(', ')}` : null,
  arr(iocs.domains) ? `    Domains : ${iocs.domains.join(', ')}` : null,
  arr(iocs.hashes)  ? `    Hashes  : ${iocs.hashes.join(', ')}` : null,
  arr(iocs.urls)    ? `    URLs    : ${iocs.urls.join(', ')}` : null,
  ``,
  `${'─'.repeat(60)}`,
  `🛡️ THREAT INTELLIGENCE`,
  `${'─'.repeat(60)}`,
  `  TI Flagged  : ${(ti.summary?.flagged||[]).join(' | ')||'None'}`,
  `  Engine Health: ${engHealth}`,
  ``,
  `  📊 Engine Results`,
  engineLines,
  ``,
  `  📈 Reputation Details`,
  repLines.join('\n') || '  None available',
  ``,
  `${'─'.repeat(60)}`,
  `⚙️ SYSCHECK`,
  `${'─'.repeat(60)}`,
  `  ${sysStr}`,
  ti.hash_rep?.hybrid?.hash_note ? `  ⚠️ Hash Mismatch: ${ti.hash_rep.hybrid.hash_note}` : null,
  ``,
  `🔓 VULNERABILITY`,
  `  ${vulnStr}`,
  ``,
  `📜 COMPLIANCE`,
  compLines || '  None',
  ``,
  `${'─'.repeat(60)}`,
  `🔎 L2 INVESTIGATION`,
  `${'─'.repeat(60)}`,
  `  Login Status : ${successDetected ? '⚠️ Possible Successful Login Detected' : '❌ No Successful Login Observed'}`,
  `  Attempts     : ${safe(alert.fired_times)} failed attempts`,
  `  ISP          : ${safe(ti.ip_rep?.abuseipdb?.isp || ti.ip_rep?.virustotal?.asn_owner)}`,
  `  TOR          : ${safe(ti.ip_rep?.abuseipdb?.is_tor)}`,
  ``,
  `  📅 Investigation Steps`,
  timelineLines || '  N/A',
  ``,
  `  🎯 Affected Assets`,
  (arr(ai.affected_assets)||[]).map(a=>`    • ${a}`).join('\n') || '  N/A',
  ``,
  arr(ai.false_positive_indicators) ? [`  ✅ False Positive Indicators`, ai.false_positive_indicators.map(f=>`    • ${f}`).join('\n')].join('\n') : null,
  arr(ai.zero_day_indicators) ? [`  ⚡ Zero-Day Indicators`, ai.zero_day_indicators.map(z=>`    • ${z}`).join('\n')].join('\n') : null,
  ai.analyst_notes ? `\n  🗒️ Analyst Notes\n    ${ai.analyst_notes}` : null,
  ``,
  `${'─'.repeat(60)}`,
  `🛠️ RECOMMENDED ACTIONS`,
  `${'─'.repeat(60)}`,
  actionLines || '  N/A',
  ``,
  `🔧 DETECTION IMPROVEMENTS`,
  improvLines,
  ``,
  `${'─'.repeat(60)}`,
  `⏱️ TIMELINE`,
  `${'─'.repeat(60)}`,
  `  Received  : ${safe(tl.received_at)}`,
  `  TI Done   : ${safe(tl.ti_completed_at)}`,
  `  AI Done   : ${safe(tl.ai_completed_at)}`,
  `  Total     : ${duration}`,
  `  AI Tokens : ${safe(AUDIT?.tokens_used)} | Latency: ${safe(AUDIT?.response_ms)}ms | Model: ${safe(AUDIT?.ai_model)}`,
  ``,
  `${'═'.repeat(60)}`,
  `🆔 ${safe(_e.alert_id)}`,
  `📅 Generated: ${new Date().toUTCString()}`,
].filter(l => l !== null).join('\n');

// ════════════════════════════════════════════════════════════════
// TELEGRAM MESSAGE — Compact
// ════════════════════════════════════════════════════════════════
const tgTI = [];
if (ti.ip_rep?.abuseipdb) {
  const a = ti.ip_rep.abuseipdb;
  tgTI.push(`  AbuseIPDB: Score=${safe(a.score)}% | ISP=${safe(a.isp)} | Reports=${safe(a.reports)} | TOR=${safe(a.is_tor)}`);
}
if (ti.ip_rep?.virustotal) {
  const v = ti.ip_rep.virustotal;
  tgTI.push(`  VT IP: Mal=${safe(v.malicious)} | Sus=${safe(v.suspicious)} | ASN=${safe(v.asn_owner)}`);
}
if (ti.domain_rep?.virustotal) {
  const v = ti.domain_rep.virustotal;
  tgTI.push(`  VT Domain: Mal=${safe(v.malicious)} | Sus=${safe(v.suspicious)}`);
}
if (ti.domain_rep?.otx) {
  const o = ti.domain_rep.otx;
  tgTI.push(`  OTX Domain: Pulses=${safe(o.pulse_count)} | ${trunc((o.malware_families||[]).join(',') || 'No families', 40)}`);
}
if (ti.url_rep?.otx) {
  const o = ti.url_rep.otx;
  tgTI.push(`  OTX URL: Pulses=${safe(o.pulse_count)} | ${trunc((o.malware_families||[]).join(',') || 'No families', 40)}`);
}
if (ti.hash_rep?.virustotal) {
  const v = ti.hash_rep.virustotal;
  tgTI.push(`  VT Hash: Mal=${safe(v.malicious)} | ${trunc(safe(v.name), 25)}`);
}
if (ti.hash_rep?.hybrid) {
  const h = ti.hash_rep.hybrid;
  tgTI.push(`  Hybrid: ${safe(h.verdict)} | Multiscan=${safe(h.multiscan_result)}% | CS=${safe(h.crowdstrike_ml)} | Family=${safe(h.family)}`);
  if (h.hash_note) tgTI.push(`  ⚠️ ${h.hash_note}`);
}

const tgActions = (arr(ai.recommended_actions)||[])
  .map(a => `  ${trunc(a, 150)}`).join('\n');

const tgTimeline = (arr(ai.investigation_timeline)||[])
  .map((s,i) => `  ${i+1}. ${trunc(String(s ?? '').replace(/^Step \d+ — /,''), 70)}`).join('\n');

const tgIOCs = [
  arr(iocs.ips)     ? `  IPs: ${iocs.ips.join(', ')}` : null,
  arr(iocs.domains) ? `  Domains: ${iocs.domains.join(', ')}` : null,
  arr(iocs.urls)    ? `  URLs: ${trunc(iocs.urls[0], 50)}` : null,
  `  Verdict: <b>${safe(ai.ioc_analysis?.ioc_verdict,'N/A').toUpperCase()}</b>`
].filter(Boolean).join('\n');

const tg = [
  `${se} <b>${(_e.severity_tier||'').toUpperCase()}</b> | Rule <code>${safe(alert.rule_id)}</code> | Level ${safe(alert.rule_level)}`,
  `🆔 <code>${safe(_e.alert_id)}</code>`,
  `📅 ${safe(alert.timestamp)}`,
  `<b>${safe(alert.rule_desc)}</b>`,
  ``,
  `🖥 <b>Host:</b> <code>${safe(host.agent_name)}</code> (${safe(host.agent_ip)}) | Env: ${safe(host.labels?.environment)} | Crit: ${safe(host.labels?.criticality)}`,
  `🌐 <b>Src:</b> <code>${safe(net.src_ip)}</code>:${safe(net.src_port)} → User: <b>${safe(net.dst_user)}</b>`,
  `📍 ${safe(net.src_country)}, ${safe(net.src_city)}`,

  // ── v5 INSERT: Burst banner — only rendered when isBurst=true (~200–250 chars max) ──
  ...tgDedupLines,

  ``,
  `${ve} | Risk: <b>${safe(ai.risk_score)}/100</b> | ${ce}`,
  `🛡 TI: ${te} | Score: ${safe(ti.summary?.score)} | ${tgEngHealth}`,
  `⚔️ <b>Attack:</b> ${safe(ai.attack_type)}`,
  `🔁 Fired: ${safe(alert.fired_times)}x | Login: ${successDetected ? '⚠️ Possible Success' : '❌ No Success'}`,
  ``,
  `📝 <b>Analysis:</b>`,
  `  ${trunc(safe(ai.analysis), 280)}`,
  ``,
  `🧬 <b>MITRE:</b> ${(mitre.techniques||[]).join(', ')||'N/A'} | ${(mitre.tactics||[]).join(', ')||'N/A'}`,
  arr(mitre.sub_techniques) ? `   Sub: ${mitre.sub_techniques.join(', ')}` : null,
  ``,
  `🔍 <b>IOCs:</b>`,
  tgIOCs,
  ``,
  `🛡 <b>TI Detail:</b>`,
  tgTI.join('\n') || '  N/A',
  ``,
  `⚙️ <b>Syscheck:</b> ${tgSys}`,
  `🔓 <b>Vuln:</b> ${tgVuln}`,
  `📜 <b>Compliance:</b> ${tgComp}`,
  ``,
  `🛠 <b>Recommended Actions:</b>`,
  tgActions || '  N/A',
  ``,
  `🔎 <b>Investigation Steps:</b>`,
  tgTimeline || '  N/A',
  ``,
  `🎯 <b>Assets:</b> ${(arr(ai.affected_assets)||[]).join(', ')||'N/A'}`,
  ai.analyst_notes ? `🗒 <b>Notes:</b> ${trunc(ai.analyst_notes, 150)}` : null,
  ``,
  `⏱ Total: ${duration} | Tokens: ${safe(AUDIT?.tokens_used)} | Model: ${safe(AUDIT?.ai_model)}`,
].filter(l => l !== null).join('\n');

// Safety trim
const finalTg = tg.length > 4000 ? tg.slice(0, 3990) + '\n...' : tg;

// Email Subject — v5: prefix [BURST] when applicable
const burstPrefix = isBurst ? `[BURST:${attackPat}] ` : '';
const subject = `${burstPrefix}[${(_e.severity_tier||'').toUpperCase()}][${ai.alert_verdict||'N/A'}][Risk:${ai.risk_score||0}] ${safe(ai.attack_type)} — ${safe(host.agent_name)} — ${safe(net.src_ip)}`;

return [{
  json: {
    summary:      lines,
    tgMessage:    finalTg,
    emailSubject: subject,
    tgCharCount:  finalTg.length,
    _e,       // ← ADD THIS
    AUDIT     // ← ADD THIS
  }
}];

const r = $input.item.json;

// n8n unwraps array — r is the first result object directly
// Check if it's a valid result by looking for sha256 field
const isError   = r.error !== undefined;
const isResult  = r.sha256 !== undefined && !isError;
const notFound  = !isResult && !isError;

return [{ json: {
  engine:       'HybridAnalysis',
  ok:           isResult,
  not_found:    notFound,
  rate_limited: false,
  status_code:  200,
  data: isResult ? [{
    verdict:        r.verdict                || null,
    threat_score:   r.threat_score           ?? null,
    multiscan_result: r.multiscan_result     ?? null,
    vx_family:      r.vx_family             || null,
    type:           r.type                  || null,
    type_short:     r.type_short            || [],
    size:           r.size                  ?? null,
    sha256:         r.sha256                || null,
    md5:            r.md5                   || null,
    tags:           r.tags                  || [],
    whitelisted:    r.whitelisted           ?? false,
    submit_name:    r.last_file_name        || null,
    submitted_at:   r.submitted_at          || null,
    crowdstrike_ml: r.scanners_v2?.crowdstrike_ml?.status || null,
    metadefender:   r.scanners_v2?.metadefender
      ? `${r.scanners_v2.metadefender.positives}/${r.scanners_v2.metadefender.total} (${r.scanners_v2.metadefender.percent}%)`
      : null
  }] : []
}}];

// ═══════════════════════════════════════════════════════════════════════
// C — AGGREGATE TI — Dynamic v3
// Handles: AbuseIPDB, VT_IP, OTX, VT_Hash, HybridAnalysis
// + Ready slots for: MalwareBazaar, VT_Domain, URLhaus
// Features:
//   → Dynamic OTX type routing (url/domain/IPv4/file)
//   → Full engine status tracking (ok/error/rate_limited/skipped/no_response)
//   → Rebalanced scoring matching AI rules
//   → url_rep section added
//   → Full Hybrid fields extracted
//   → Hash mismatch detection
//   → Unknown engine fallback handler
// ═══════════════════════════════════════════════════════════════════════

// ── 1. Restore _e ──────────────────────────────────────────────────────
const _e   = JSON.parse(JSON.stringify($('C — Extract IOCs').first().json._e));
const items = $input.all();

if (!_e.alert_id) throw new Error('INTEGRITY: alert_id missing — check Extract IOCs node');

// ── 2. Index all engine results by name ────────────────────────────────
const byEngine = {};
items.forEach(item => {
  const j = item.json;
  if (j && j.engine) byEngine[j.engine] = j;
});

// ── 3. IOC availability flags ──────────────────────────────────────────
const NO_IP   = !_e.iocs.ips[0];
const NO_DOM  = !_e.iocs.domains[0];
const NO_URL  = !_e.iocs.urls[0];
const NO_HASH = !_e.iocs.hashes[0];

// ── 4. Initialize TI structure ─────────────────────────────────────────
const ti = {
  ip_rep:     {},
  domain_rep: {},
  url_rep:    {},
  hash_rep:   {},
  summary: {
    score:   0,
    flagged: [],
    verdict: 'unknown'
  },
  engines: {
    AbuseIPDB:      NO_IP             ? 'skipped(no_ip)'   : 'no_response',
    VT_IP:          NO_IP             ? 'skipped(no_ip)'   : 'no_response',
    VT_Domain:      NO_DOM            ? 'skipped(no_dom)'  : 'no_response',
    OTX:            (NO_URL && NO_DOM) ? 'skipped(no_url_dom)' : 'no_response',
    VT_Hash:        NO_HASH           ? 'skipped(no_hash)' : 'no_response',
    HybridAnalysis: NO_HASH           ? 'skipped(no_hash)' : 'no_response',
  },
  engine_detail: {}  // full raw status per engine for debugging
};

// ── Helper: safe score add with cap ───────────────────────────────────
const addScore = (pts, reason) => {
  ti.summary.score = Math.min(100, ti.summary.score + pts);
  if (reason) ti.summary.flagged.push(reason);
};

// ── Helper: mark engine status ────────────────────────────────────────
const markEngine = (name, status, detail = null) => {
  ti.engines[name] = status;
  if (detail) ti.engine_detail[name] = detail;
};

// ═══════════════════════════════════════════════════════════════════════
// ENGINE HANDLERS
// ═══════════════════════════════════════════════════════════════════════

// ── AbuseIPDB ──────────────────────────────────────────────────────────
const ab = byEngine['AbuseIPDB'];
if (ab) {
  if (NO_IP) {
    markEngine('AbuseIPDB', 'skipped(no_ip)');
  } else if (ab.rate_limited) {
    markEngine('AbuseIPDB', 'rate_limited_429');
  } else if (!ab.ok) {
    markEngine('AbuseIPDB', 'error', ab.data?.error?.message || 'unknown_error');
  } else {
    const d  = ab.data?.data || {};
    const sc = Number(d.abuseConfidenceScore || 0);
    const isTor = d.isTor || false;

    ti.ip_rep.abuseipdb = {
      ip:           d.ipAddress,
      score:        sc,
      country:      d.countryCode,
      country_name: d.countryName,
      isp:          d.isp,
      domain:       d.domain,
      usage_type:   d.usageType,
      reports:      d.totalReports,
      distinct_users: d.numDistinctUsers,
      last_reported: d.lastReportedAt,
      is_tor:       isTor,
      hostnames:    d.hostnames || [],
      is_public:    d.isPublic,
      is_whitelisted: d.isWhitelisted
    };
    markEngine('AbuseIPDB', 'ok');

    // Scoring — Rule 15 from AI prompt
    if (isTor) {
      addScore(10, `IP ${d.ipAddress} AbuseIPDB=TOR_EXIT_NODE`);
    }
    if (sc > 80) {
      addScore(10, `IP ${d.ipAddress} AbuseIPDB=${sc}% HIGH_CONFIDENCE`);
    } else if (sc > 50) {
      addScore(5,  `IP ${d.ipAddress} AbuseIPDB=${sc}% MEDIUM_CONFIDENCE`);
    } else if (sc > 20) {
      addScore(2,  `IP ${d.ipAddress} AbuseIPDB=${sc}% LOW_CONFIDENCE`);
    }
    // Note scanme.nmap.org and similar test IPs
    if ((d.hostnames || []).includes('scanme.nmap.org')) {
      ti.ip_rep.abuseipdb.note = 'Known test IP — scanme.nmap.org (Nmap official)';
    }
  }
}

// ── VT IP ──────────────────────────────────────────────────────────────
const vtip = byEngine['VT_IP'];
if (vtip) {
  if (NO_IP) {
    markEngine('VT_IP', 'skipped(no_ip)');
  } else if (vtip.rate_limited) {
    markEngine('VT_IP', 'rate_limited_429');
  } else if (!vtip.ok) {
    markEngine('VT_IP', 'error', vtip.data?.error?.message || 'connection_failed');
  } else {
    const d  = vtip.data?.data || {};
    const s  = (d.attributes || {}).last_analysis_stats || {};
    const mal = s.malicious || 0;
    const sus = s.suspicious || 0;

    ti.ip_rep.virustotal = {
      ip:         d.id,
      malicious:  mal,
      suspicious: sus,
      harmless:   s.harmless || 0,
      undetected: s.undetected || 0,
      country:    d.attributes?.country,
      asn:        d.attributes?.asn,
      asn_owner:  d.attributes?.as_owner,
      network:    d.attributes?.network,
      reputation: d.attributes?.reputation || 0
    };
    markEngine('VT_IP', 'ok');

    // Scoring — Rule 16 from AI prompt
    if (mal >= 10) {
      addScore(15, `IP ${d.id} VT-malicious=${mal} CONFIRMED`);
    } else if (mal >= 3) {
      addScore(8,  `IP ${d.id} VT-malicious=${mal} SUSPICIOUS`);
    } else if (mal >= 1) {
      addScore(3,  `IP ${d.id} VT-malicious=${mal} LOW_CONFIDENCE`);
    }
    if (sus >= 3) {
      addScore(2, `IP ${d.id} VT-suspicious=${sus}`);
    }
  }
}

// ── VT Domain ──────────────────────────────────────────────────────────
const vtdom = byEngine['VT_Domain'];
if (vtdom) {
  if (NO_DOM) {
    markEngine('VT_Domain', 'skipped(no_dom)');
  } else if (vtdom.rate_limited) {
    markEngine('VT_Domain', 'rate_limited_429');
  } else if (!vtdom.ok) {
    markEngine('VT_Domain', 'error', vtdom.data?.error?.message || 'connection_failed');
  } else {
    const d  = vtdom.data?.data || {};
    const s  = (d.attributes || {}).last_analysis_stats || {};
    const mal = s.malicious || 0;

    ti.domain_rep.virustotal = {
      domain:     d.id,
      malicious:  mal,
      suspicious: s.suspicious || 0,
      harmless:   s.harmless || 0,
      categories: d.attributes?.categories || {},
      reputation: d.attributes?.reputation || 0,
      registrar:  d.attributes?.registrar || null,
      created:    d.attributes?.creation_date || null
    };
    markEngine('VT_Domain', 'ok');

    if (mal >= 10) {
      addScore(15, `Domain ${d.id} VT-malicious=${mal} CONFIRMED`);
    } else if (mal >= 3) {
      addScore(8,  `Domain ${d.id} VT-malicious=${mal} SUSPICIOUS`);
    } else if (mal >= 1) {
      addScore(3,  `Domain ${d.id} VT-malicious=${mal} LOW_CONFIDENCE`);
    }
  }
}

// ── OTX — Dynamic type routing ─────────────────────────────────────────
const otx = byEngine['OTX'];
if (otx) {
  const hasTarget = !NO_URL || !NO_DOM;
  if (!hasTarget) {
    markEngine('OTX', 'skipped(no_url_dom)');
  } else if (otx.rate_limited) {
    markEngine('OTX', 'rate_limited_429');
  } else if (!otx.ok) {
    markEngine('OTX', 'error', otx.data?.error?.message || 'connection_failed');
  } else {
    const d    = otx.data || {};
    const type = d.type || 'unknown';  // 'url', 'domain', 'IPv4', 'FileHash-SHA256'
    const pc   = d.pulse_info?.count || 0;
    const pulses = (d.pulse_info?.pulses || []).slice(0, 5).map(p => ({
      name:             p.name,
      tags:             p.tags || [],
      malware_families: (p.malware_families || []).map(m => m.display_name),
      adversary:        p.adversary || null,
      targeted_countries: p.targeted_countries || [],
      created:          p.created || null
    }));
    const malware_families = d.pulse_info?.related?.alienvault?.malware_families || [];
    const adversary        = d.pulse_info?.related?.alienvault?.adversary || [];

    const otxData = {
      indicator:        d.indicator,
      type,
      pulse_count:      pc,
      pulses,
      malware_families,
      adversary,
      whois:            d.whois || null,
      alexa:            d.alexa || null,
      validation:       d.validation || [],
      false_positive:   d.false_positive || []
    };

    // Route to correct rep bucket based on OTX type
    if (type === 'url') {
      ti.url_rep.otx = otxData;
      markEngine('OTX', 'ok(url)');
    } else if (type === 'domain' || type === 'hostname') {
      ti.domain_rep.otx = otxData;
      markEngine('OTX', 'ok(domain)');
    } else if (type === 'IPv4' || type === 'IPv6') {
      ti.ip_rep.otx = otxData;
      markEngine('OTX', 'ok(ip)');
    } else if (type === 'FileHash-SHA256' || type === 'FileHash-MD5') {
      ti.hash_rep.otx = otxData;
      markEngine('OTX', 'ok(hash)');
    } else {
      // Unknown type — store in url_rep as fallback
      ti.url_rep.otx = otxData;
      markEngine('OTX', `ok(unknown_type:${type})`);
    }

    // Scoring
    if (pc > 0) {
      const pts = Math.min(pc * 2, 10);
      addScore(pts, `OTX ${type}=${d.indicator} pulses=${pc}`);
    }
    if (malware_families.length > 0) {
      addScore(3, `OTX malware_families=${malware_families.join(',')}`);
    }
  }
}

// ── VT Hash ────────────────────────────────────────────────────────────
const vthash = byEngine['VT_Hash'];
if (vthash) {
  if (NO_HASH) {
    markEngine('VT_Hash', 'skipped(no_hash)');
  } else if (vthash.rate_limited) {
    markEngine('VT_Hash', 'rate_limited_429');
  } else if (!vthash.ok) {
    markEngine('VT_Hash', 'error', vthash.data?.error?.message || 'connection_failed');
  } else {
    const d  = vthash.data?.data || {};
    const s  = (d.attributes || {}).last_analysis_stats || {};
    const mal = s.malicious || 0;

    ti.hash_rep.virustotal = {
      hash:        d.id,
      malicious:   mal,
      suspicious:  s.suspicious || 0,
      harmless:    s.harmless || 0,
      undetected:  s.undetected || 0,
      name:        d.attributes?.meaningful_name || null,
      type:        d.attributes?.type_description || null,
      size:        d.attributes?.size || null,
      first_seen:  d.attributes?.first_submission_date || null,
      last_seen:   d.attributes?.last_submission_date || null,
      reputation:  d.attributes?.reputation || 0,
      tags:        d.attributes?.tags || []
    };
    markEngine('VT_Hash', 'ok');

    // Scoring — Rule 16
    if (mal >= 10) {
      addScore(20, `Hash ${d.id} VT-malicious=${mal} CONFIRMED_MALWARE`);
    } else if (mal >= 3) {
      addScore(10, `Hash ${d.id} VT-malicious=${mal} SUSPICIOUS`);
    } else if (mal >= 1) {
      addScore(4,  `Hash ${d.id} VT-malicious=${mal} LOW_CONFIDENCE`);
    }
  }
}

// ── Hybrid Analysis ────────────────────────────────────────────────────
const hyb = byEngine['HybridAnalysis'];
if (hyb) {
  if (NO_HASH) {
    markEngine('HybridAnalysis', 'skipped(no_hash)');
  } else if (hyb.rate_limited) {
    markEngine('HybridAnalysis', 'rate_limited_429');
  } else if (!hyb.ok) {
    markEngine('HybridAnalysis', 'error', 'no_result_or_not_found');
  } else {
    // Hybrid returns array — get first result
    const results = Array.isArray(hyb.data) ? hyb.data : [];
    const first   = results[0] || {};

    if (!first.verdict && !first.sha256) {
      markEngine('HybridAnalysis', 'ok_no_verdict');
    } else {
      // Hash mismatch detection
      const submittedHash   = _e.iocs.hashes[0] || '';
      const returnedHash    = (first.sha256 || '').toLowerCase();
      const hashMatch       = submittedHash.toLowerCase() === returnedHash;

      ti.hash_rep.hybrid = {
        verdict:          first.verdict || null,
        threat_score:     first.threat_score ?? null,
        multiscan_result: first.multiscan_result ?? null,
        crowdstrike_ml:   first.crowdstrike_ml || null,
        metadefender:     first.metadefender || null,
        family:           first.vx_family || null,
        type:             first.type || null,
        type_short:       first.type_short || [],
        size:             first.size ?? null,
        sha256:           first.sha256 || null,
        md5:              first.md5 || null,
        tags:             first.tags || [],
        whitelisted:      first.whitelisted ?? false,
        submitted_at:     first.submitted_at || null,
        hash_match:       hashMatch,
        hash_note:        !hashMatch && returnedHash
          ? `Returned hash ${returnedHash.slice(0,16)}... differs from queried ${submittedHash.slice(0,16)}...`
          : null
      };
      markEngine('HybridAnalysis', 'ok');

      // Scoring — rebalanced
      if (first.verdict === 'malicious') {
        addScore(15, `Hash Hybrid=MALICIOUS family=${first.vx_family || 'unknown'}`);
        if ((first.multiscan_result || 0) > 80) {
          addScore(5, `Hash Hybrid multiscan=${first.multiscan_result}%`);
        }
        if (first.crowdstrike_ml === 'malicious') {
          addScore(5, 'Hash CrowdStrike=MALICIOUS');
        }
        if (!hashMatch && returnedHash) {
          ti.summary.flagged.push(`Hash mismatch: queried=${submittedHash.slice(0,16)} returned=${returnedHash.slice(0,16)}`);
        }
      } else if (first.verdict === 'suspicious') {
        addScore(8, `Hash Hybrid=SUSPICIOUS family=${first.vx_family || 'unknown'}`);
      } else if (first.verdict === 'whitelisted') {
        // Whitelisted — subtract score
        ti.summary.score = Math.max(0, ti.summary.score - 5);
      }
    }
  }
}

// ── Unknown engines — dynamic fallback ────────────────────────────────
const knownEngines = new Set([
  'AbuseIPDB','VT_IP','VT_Domain','OTX',
  'VT_Hash','HybridAnalysis','MalwareBazaar','URLhaus'
]);
items.forEach(item => {
  const name = item.json?.engine;
  if (name && !knownEngines.has(name)) {
    // Unknown engine — store raw in url_rep as generic
    ti.engines[name] = item.json?.ok ? 'ok(unknown_engine)' : 'error(unknown_engine)';
    ti.engine_detail[name] = {
      ok:   item.json?.ok,
      data: item.json?.data
    };
  }
});

// ═══════════════════════════════════════════════════════════════════════
// FINAL VERDICT SCORING
// ═══════════════════════════════════════════════════════════════════════
const score = ti.summary.score;

if      (score >= 20) ti.summary.verdict = 'malicious';
else if (score >= 10) ti.summary.verdict = 'suspicious';
else if (score >  0)  ti.summary.verdict = 'low_risk';
else                  ti.summary.verdict = 'clean';

// ── Engine health summary ──────────────────────────────────────────────
const engineStatuses  = Object.values(ti.engines);
ti.summary.engines_ok      = engineStatuses.filter(s => s.startsWith('ok')).length;
ti.summary.engines_error   = engineStatuses.filter(s => s === 'error' || s.includes('failed')).length;
ti.summary.engines_skipped = engineStatuses.filter(s => s.startsWith('skipped')).length;
ti.summary.engines_limited = engineStatuses.filter(s => s.includes('429')).length;
ti.summary.engines_total   = engineStatuses.length;

// ── Attach to _e ──────────────────────────────────────────────────────
_e.threat_intel = ti;
_e.timeline.ti_completed_at = new Date().toISOString();

return [{ json: { _e } }];

// 1. Capture all incoming items from the previous node
const items = $input.all();

// 2. Logic: Pick the 2nd item (index 1) if it exists, otherwise fallback to the 1st
// This prevents the code from crashing if the AI only sends one result.
let targetItem = items.length >= 2 ? items[1].json : items[0].json;

/**
 * 3. THE FIX FOR REPETITION:
 * We return an array with exactly ONE element. 
 * Even if 100 items came in, only 1 item goes out.
 */
return [{
  json: {
    ...targetItem,
    // Add a unique execution ID or timestamp for your SOC audit logs
    extraction_timestamp: new Date().toISOString(),
    item_count_received: items.length
  }
}];

// ═══════════════════════════════════════════════════════════════
// PARSE AI + BUILD AUDIT — Gemini Optimized
// ═══════════════════════════════════════════════════════════════

// 1. Restore _e from the TI node
const _e = JSON.parse(JSON.stringify($('C — Aggregate TI').first().json._e));

// 2. Direct Access (since we deduplicated)
const item = $input.first().json;
const rawText = item?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

// 3. Clean and Strip Markdown
let raw = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

// 4. Parse AI JSON
let ai = {};
try {
  ai = JSON.parse(raw);
} catch (e) {
  ai = {
    alert_summary: `[PARSE ERROR] Invalid Gemini JSON`,
    alert_verdict: 'NEEDS_INVESTIGATION',
    incident_severity: 'HIGH',
    risk_score: 50,
    analysis: `Failed to parse. Raw snippet: ${raw.slice(0, 150)}`,
    recommended_actions: ['P0 — Manual review required']
  };
}

// 5. Enrichment & Tiering
_e.ai_analysis = ai;
_e.timeline.ai_completed_at = new Date().toISOString();

const lvl = _e.alert.rule_level || 0;
let tier = 'low';
if      (lvl >= 12) tier = 'critical';
else if (lvl >= 9)  tier = 'high';
else if (lvl >= 6)  tier = 'medium';
if (ai.incident_severity === 'CRITICAL') tier = 'critical';

_e.severity_tier = tier;
_e.is_malicious  = (_e.threat_intel?.summary?.verdict === 'malicious' || ai.alert_verdict === 'TRUE_POSITIVE');

// 6. Final AUDIT Object (Summarizer-Ready)
const AUDIT = {
  alert_id: _e.alert_id,
  pipeline: _e.pipeline,
  host: { ..._e.host },
  alert: { ..._e.alert },
  iocs: { ..._e.iocs },
  threat_intel: {
    verdict: _e.threat_intel?.summary?.verdict,
    score: _e.threat_intel?.summary?.score,
    flagged: _e.threat_intel?.summary?.flagged,
    engines: _e.threat_intel?.engines
  },
  analysis: {
    verdict:      ai.alert_verdict,
    confidence:   ai.confidence,
    severity:     ai.incident_severity,
    risk_score:   ai.risk_score || 0,
    attack_type:  ai.attack_type,
    summary:      ai.alert_summary,
    detail:       ai.analysis,
    mitre_mapped: ai.mitre_attack || {},
    ioc_verdict:  ai.ioc_analysis || {},
    timeline:     ai.investigation_timeline || [],
    assets:       ai.affected_assets || [],
    actions:      ai.recommended_actions || [],
    improvements: ai.detection_improvements || [],
    fp_indicators: ai.false_positive_indicators || [],
    threat_actor: ai.threat_actor_profile || null,
    zero_day:     ai.zero_day_indicators || [],
    analyst_notes: ai.analyst_notes || null
  },
  response: {
    severity_tier: tier,
    is_malicious:  _e.is_malicious
  },
  ai_provider: 'Gemini',
  ai_model:    item.modelVersion || 'gemini-lite',
  tokens_used: item.usageMetadata?.totalTokenCount || 0,
  response_ms: Date.now() - new Date(_e.timeline.received_at).getTime(),
  timeline: {
    ..._e.timeline,
    total_ms: Date.now() - new Date(_e.timeline.received_at).getTime()
  }
};

return [{ json: { _e, AUDIT } }];

const raw = $input.item.json;

// ══════════════════════════════════════════════════════════════════
// BODY UNWRAPPING — handles all 3 nesting levels n8n can produce:
//
//   Level 1 — Direct raw alert (txt-file / raw Wazuh):
//     raw = { rule, agent, data, ... }
//
//   Level 2 — Standard webhook POST:
//     raw = { body: { pipeline, rule_id, alert: {...} }, ... }
//
//   Level 3 — Curl / n8n test mode (double-wrapped):
//     raw = { body: [ { body: { pipeline, rule_id, alert: {...} } } ] }
//
// ══════════════════════════════════════════════════════════════════
let body;
if (Array.isArray(raw.body)) {
  // Level 3: body is an array — unwrap to body[0].body (actual payload)
  body = raw.body[0]?.body || raw.body[0] || raw;
} else if (raw.body !== undefined) {
  // Level 2: standard single-wrapped webhook
  body = raw.body;
} else {
  // Level 1: raw IS the alert object directly
  body = raw;
}

// ══════════════════════════════════════════════════════════════════
// FORMAT AUTO-DETECTION
// Webhook format : body has flat pipeline/rule_id/rule_level at root
// Raw Wazuh format: body IS the alert object (has rule{}, agent{} at root)
// ══════════════════════════════════════════════════════════════════
const isWebhookFormat = (
  body.pipeline   !== undefined ||
  body.rule_id    !== undefined ||
  body.rule_level !== undefined
);

// ── Safe getter ──────────────────────────────────────────────────
const s = (v, d = null) => (v !== undefined && v !== null && v !== '') ? v : d;

// ══════════════════════════════════════════════════════════════════
// RESOLVE NESTED BLOCKS — handle both formats
// ══════════════════════════════════════════════════════════════════
let rule, agent, data, sys, win, winSys, winEvt, vuln, geo,
    predecoder, suricataAlert, fullLog;

if (isWebhookFormat) {
  // ── WEBHOOK FORMAT ────────────────────────────────────────────
  const alert  = body.alert || {};
  rule         = alert.rule  || {};
  agent        = alert.agent || {};
  data         = alert.data  || {};
  // syscheck: prefer alert.syscheck, fallback body.syscheck (raw FIM alerts)
  sys          = alert.syscheck    || body.syscheck    || {};
  // GeoLocation: prefer alert.GeoLocation, fallback body.GeoLocation
  geo          = alert.GeoLocation || body.GeoLocation || {};
  fullLog      = s(alert.full_log) || s(body.full_log) || '';
  predecoder   = alert.predecoder  || body.predecoder  || {};

  // Windows event blocks — support both eventData (capital D) and eventdata (lowercase d)
  win    = data.win  || {};
  winSys = win.system    || {};
  winEvt = win.eventData || win.eventdata || {};

  // Vulnerability block (Apache/Log4Shell style — inside data)
  vuln          = data.vulnerability || {};
  // Suricata IDS nested alert block (data.alert)
  suricataAlert = data.alert || {};

} else {
  // ── RAW WAZUH FORMAT (txt-file / direct Wazuh alert JSON) ─────
  rule          = body.rule   || {};
  agent         = body.agent  || {};
  data          = body.data   || {};
  // syscheck and GeoLocation sit at ROOT level in raw format
  sys           = body.syscheck    || {};
  geo           = body.GeoLocation || {};
  fullLog       = s(body.full_log) || '';
  predecoder    = body.predecoder  || {};

  // Windows event blocks — support both casings
  win    = data.win  || {};
  winSys = win.system    || {};
  winEvt = win.eventData || win.eventdata || {};

  // Vulnerability block
  vuln          = data.vulnerability || {};
  // Suricata IDS nested alert block
  suricataAlert = data.alert || {};
}

// ══════════════════════════════════════════════════════════════════
// CORE FIELDS
// Flat webhook root fields take priority → nested alert as fallback
// ══════════════════════════════════════════════════════════════════
const alertObj  = isWebhookFormat ? (body.alert || {}) : body;

const level     = Number(s(body.rule_level) ?? s(rule.level,       0));
const ruleId    = String(s(body.rule_id)    ?? s(rule.id,    'unknown'));
const agentName =        s(body.agent_name) ?? s(agent.name, 'unknown');
const agentIp   =        s(body.agent_ip)   ?? s(agent.ip,   'unknown');
const agentId   =        s(body.agent_id)   ?? s(agent.id,   'unknown');
const location  =        s(body.location)   ?? s(alertObj.location, 'unknown');
const timestamp =        s(body.timestamp)  ?? s(alertObj.timestamp, new Date().toISOString());
const ruleDesc  =        s(body.rule_desc)  ?? s(rule.description, 'No description');
const ruleGroups=        s(body.rule_groups)?? s(rule.groups, []);
const managerId =        s(alertObj.manager?.name) || 'unknown';

const receivedAt = new Date().toISOString();
const alert_id   = `crit-${ruleId}-${agentName.replace(/[^a-z0-9]/gi, '-')}-${Date.now()}`;

// ══════════════════════════════════════════════════════════════════
// HASH PARSER — handles "MD5=aaa,SHA256=bbb,SHA1=ccc" strings
// Used for: Sysmon EID1/10/11 hashes field
// ══════════════════════════════════════════════════════════════════
const parseHashes = (hashStr) => {
  if (!hashStr || typeof hashStr !== 'string') return {};
  const result = {};
  const pairs  = hashStr.split(',');
  for (const pair of pairs) {
    const eq  = pair.indexOf('=');
    if (eq === -1) continue;
    const key = pair.slice(0, eq).trim().toLowerCase();
    const val = pair.slice(eq + 1).trim();
    if (val) result[key] = val;
  }
  return result;
};

const rawHashes    = s(winEvt.hashes) || '';
const parsedHashes = parseHashes(rawHashes);

// ══════════════════════════════════════════════════════════════════
// IOC SEEDS — comprehensive extraction across all alert types
// ══════════════════════════════════════════════════════════════════

// Source IP
const src_ip =
  s(data.srcip)        ||
  s(data.src_ip)       ||
  s(winEvt.sourceIp)   ||
  s(winEvt.ipAddress)  ||
  null;

// Destination IP (Sysmon EID3 / Suricata)
const dst_ip =
  s(winEvt.destinationIp) ||
  s(data.dest_ip)          ||
  null;

// URL seed
const url = s(data.url) || null;

// Domain seed
const domain =
  s(data.hostname)                                              ||
  s(winEvt.destinationHostname)                                 ||
  (url ? (url.match(/https?:\/\/([^/?#]+)/) || [])[1] : null)  ||
  (() => {
    // Extract from PS scriptBlockText download cradle
    const sbt = s(winEvt.scriptBlockText) || '';
    const m   = sbt.match(/https?:\/\/([^/\s'"]+)/);
    return m ? m[1] : null;
  })()                                                          ||
  null;

// Hash seeds — both SHA256 and MD5 extracted separately
const hash_sha256 =
  parsedHashes.sha256 ||
  s(sys.sha256_after) ||
  s(data.sha256)      ||
  null;

const hash_md5 =
  parsedHashes.md5  ||
  s(sys.md5_after)  ||
  s(data.md5)       ||
  null;

// Legacy single hash (sha256 preferred)
const hash = hash_sha256 || hash_md5 || null;

// ══════════════════════════════════════════════════════════════════
// GEO ENRICHMENT
// ══════════════════════════════════════════════════════════════════
const geoInfo = {
  city:    s(geo.city_name),
  country: s(geo.country_name),
  lat:     s(geo.location?.lat),
  lon:     s(geo.location?.lon)
};

// ══════════════════════════════════════════════════════════════════
// COMPLIANCE TAGS
// ══════════════════════════════════════════════════════════════════
const compliance = {
  pci_dss:     s(rule.pci_dss,     []),
  gdpr:        s(rule.gdpr,        []),
  hipaa:       s(rule.hipaa,       []),
  nist_800_53: s(rule.nist_800_53, [])
};

// ══════════════════════════════════════════════════════════════════
// AGENT LABELS
// ══════════════════════════════════════════════════════════════════
const agentLabels = {
  environment: s(agent.labels?.environment),
  criticality: s(agent.labels?.criticality)
};

// ══════════════════════════════════════════════════════════════════
// SYSMON WINDOWS SYSTEM BLOCK
// EID, channel, computer, provider, record ID
// ══════════════════════════════════════════════════════════════════
const sysmonSystem = {
  event_id:      s(winSys.eventID),
  provider_name: s(winSys.providerName),
  channel:       s(winSys.channel),
  computer:      s(winSys.computer),
  record_id:     s(winSys.eventRecordID),
  severity:      s(winSys.severityValue),
  utc_time:      s(winSys.systemTime)
};

// ══════════════════════════════════════════════════════════════════
// SYSMON PROCESS BLOCK
// EID1 (process create), EID8 (CreateRemoteThread),
// EID10 (process access), EID11 (file create),
// EID13 (registry), EID4104 (PS script block)
// ══════════════════════════════════════════════════════════════════
const sysmonProcess = {
  // Source / attacker process
  source_image:        s(winEvt.sourceImage)        || s(winEvt.image)       || null,
  source_process_id:   s(winEvt.sourceProcessId)    || s(winEvt.processId)   || null,
  source_process_guid: s(winEvt.sourceProcessGuid)  || s(winEvt.processGuid) || null,
  source_user:         s(winEvt.sourceUser)          || s(winEvt.user)        || null,

  // Target / victim process
  target_image:        s(winEvt.targetImage)         || null,
  target_process_id:   s(winEvt.targetProcessId)     || null,
  target_process_guid: s(winEvt.targetProcessGuid)   || null,
  target_user:         s(winEvt.targetUser)          || null,

  // Parent process (EID1)
  parent_image:        s(winEvt.parentImage)         || null,
  parent_process_id:   s(winEvt.parentProcessId)     || null,
  parent_cmdline:      s(winEvt.parentCommandLine)   || null,
  parent_user:         s(winEvt.parentUser)          || null,

  // Execution context
  command_line:        s(winEvt.commandLine)         || s(data.command) || null,
  current_directory:   s(winEvt.currentDirectory)    || null,
  integrity_level:     s(winEvt.integrityLevel)      || null,
  logon_id:            s(winEvt.logonId)             || null,

  // Process access (EID10)
  granted_access:      s(winEvt.grantedAccess)       || null,
  call_trace:          s(winEvt.callTrace)           || null,

  // Remote thread (EID8)
  new_thread_id:       s(winEvt.newThreadId)         || null,
  start_address:       s(winEvt.startAddress)        || null,

  // File create (EID11)
  target_filename:     s(winEvt.targetFilename)      || null,

  // Registry (EID13)
  target_object:       s(winEvt.targetObject)        || null,
  details:             s(winEvt.details)             || null,

  // Hashes — parsed from "MD5=x,SHA256=y,SHA1=z" + individual fields
  hashes: {
    raw:    rawHashes    || null,
    md5:    hash_md5,
    sha256: hash_sha256,
    sha1:   parsedHashes.sha1 || null
  },

  // PowerShell script block (EID4104)
  script_block_text:   s(winEvt.scriptBlockText)    || null,
  script_block_id:     s(winEvt.scriptBlockId)      || null,

  // Sysmon rule tag (e.g. "technique_id=T1003,technique_name=Credential Dumping")
  rule_name:           s(winEvt.ruleName)            || null
};

// ══════════════════════════════════════════════════════════════════
// SYSMON NETWORK BLOCK (EID3 — network connection)
// ══════════════════════════════════════════════════════════════════
const sysmonNetwork = {
  src_ip:        s(winEvt.sourceIp)            || null,
  src_port:      s(winEvt.sourcePort)          || s(data.srcport)   || null,
  src_hostname:  s(winEvt.sourceHostname)      || null,
  dst_ip,
  dst_port:      s(winEvt.destinationPort)     || s(data.dest_port) || null,
  dst_hostname:  s(winEvt.destinationHostname) || null,
  dst_port_name: s(winEvt.destinationPortName) || null,
  protocol:      s(winEvt.protocol)            || s(data.protocol, 'unknown'),
  initiated:     s(winEvt.initiated)           || null,
  process_image: s(winEvt.image)               || null
};

// ══════════════════════════════════════════════════════════════════
// SURICATA IDS BLOCK
// ══════════════════════════════════════════════════════════════════
const suricataBlock = {
  action:       s(suricataAlert.action),
  signature:    s(suricataAlert.signature),
  signature_id: s(suricataAlert.signature_id),
  category:     s(suricataAlert.category),
  severity:     s(suricataAlert.severity),
  gid:          s(suricataAlert.gid),
  rev:          s(suricataAlert.rev),
  // Suricata network fields (snake_case at data root)
  src_ip:       s(data.srcip)     || s(data.src_ip)   || null,
  src_port:     s(data.srcport)   || s(data.src_port) || null,
  dst_ip:       s(data.dest_ip)   || null,
  dst_port:     s(data.dest_port) || null,
  proto:        s(data.proto)     || null,
  alert_ts:     s(data.timestamp) || null
};

// ══════════════════════════════════════════════════════════════════
// PREDECODER BLOCK (SSH / Linux syslog alerts)
// ══════════════════════════════════════════════════════════════════
const predecoderBlock = {
  program_name: s(predecoder.program_name),
  hostname:     s(predecoder.hostname),
  timestamp:    s(predecoder.timestamp)
};

// ══════════════════════════════════════════════════════════════════
// SYSCHECK BLOCK (FIM)
// Works for both root-level (raw format) and alert.syscheck (webhook)
// ══════════════════════════════════════════════════════════════════
const syscheckBlock = {
  path:               s(sys.path),
  event:              s(sys.event),
  mode:               s(sys.mode),
  sha256_after:       s(sys.sha256_after),
  sha256_before:      s(sys.sha256_before),
  md5_after:          s(sys.md5_after),
  md5_before:         s(sys.md5_before),
  sha1_after:         s(sys.sha1_after),
  sha1_before:        s(sys.sha1_before),
  size_after:         s(sys.size_after),
  size_before:        s(sys.size_before),
  uname_after:        s(sys.uname_after),
  uid_after:          s(sys.uid_after),
  mtime_after:        s(sys.mtime_after),
  changed_attributes: s(sys.changed_attributes, []),
  modified_by:        s(sys.audit?.user?.name),
  process:            s(sys.audit?.process?.name),
  process_id:         s(sys.audit?.process?.id)
};

// ══════════════════════════════════════════════════════════════════
// VULNERABILITY BLOCK
// ══════════════════════════════════════════════════════════════════
const vulnBlock = {
  cve:      s(vuln.cve),
  severity: s(vuln.severity),
  title:    s(vuln.title),
  pkg:      s(vuln.package?.name),
  version:  s(vuln.package?.version)
};

// ══════════════════════════════════════════════════════════════════
// DECODER INFO
// ══════════════════════════════════════════════════════════════════
const decoderBlock = {
  name:   s(alertObj.decoder?.name),
  parent: s(alertObj.decoder?.parent)
};

// ══════════════════════════════════════════════════════════════════
// FINAL OUTPUT
// ══════════════════════════════════════════════════════════════════
return [{
  json: {
    _e: {
      alert_id,
      pipeline:     'critical',
      input_format: isWebhookFormat ? 'webhook' : 'raw_wazuh',
      received_at:  receivedAt,

      host: {
        agent_id:   agentId,
        agent_name: agentName,
        agent_ip:   agentIp,
        manager:    managerId,
        location,
        os:         s(agent.os?.name) || null,
        computer:   s(winSys.computer) || null,
        labels:     agentLabels,
        geo:        geoInfo
      },

      alert: {
        rule_id:     ruleId,
        rule_desc:   ruleDesc,
        rule_level:  level,
        rule_groups: ruleGroups,
        fired_times: s(rule.firedtimes, 1),
        timestamp,
        decoder:     decoderBlock,
        mitre: {
          id:        s(rule.mitre?.id,        []),
          tactic:    s(rule.mitre?.tactic,    []),
          technique: s(rule.mitre?.technique, [])
        },
        compliance,
        full_log: fullLog
      },

      // Sysmon Windows event system metadata
      sysmon_system: sysmonSystem,

      // Sysmon process telemetry (EID1/8/10/11/13/4104)
      sysmon_process: sysmonProcess,

      // Sysmon network telemetry (EID3)
      sysmon_network: sysmonNetwork,

      // Suricata IDS alert
      suricata: suricataBlock,

      // Syslog predecoder (SSH / Linux)
      predecoder: predecoderBlock,

      // File Integrity Monitoring
      syscheck: syscheckBlock,

      // Vulnerability data
      vulnerability: vulnBlock,

      // Network block (kept for downstream compatibility)
      network: {
        src_ip,
        src_port:     s(data.srcport)              || s(winEvt.sourcePort)      || null,
        dst_ip,
        dst_port:     s(winEvt.destinationPort)    || s(data.dest_port)         || null,
        dst_user:     s(data.dstuser)              || null,
        dst_hostname: s(winEvt.destinationHostname)|| null,
        src_country:  s(data.srcip_country)        || s(geo.country_name)       || null,
        src_city:     s(data.srcip_city)           || s(geo.city_name)          || null,
        protocol:     s(winEvt.protocol)           || s(data.protocol)          || s(data.proto) || 'unknown'
      },

      // IOC seeds for downstream threat intel nodes
      _seeds: {
        src_ip,
        dst_ip,
        domain,
        url,
        hash_sha256,
        hash_md5,
        hash  // legacy single hash field
      },

      iocs:          { ips: [], domains: [], urls: [], hashes: [] },
      threat_intel:  {},
      ai_analysis:   {},
      severity_tier: level >= 15 ? 'critical' : level >= 12 ? 'high' : level >= 7 ? 'medium' : 'low',
      is_malicious:  false,

      timeline: {
        received_at:     receivedAt,
        enriched_at:     new Date().toISOString(),
        ti_completed_at: null,
        ai_completed_at: null,
        total_ms:        null
      }
    }
  }
}];

// ═══════════════════════════════════════════════════════
// C — Alert Dedup Gate  v2  (Aggregate + Flush)
//
// FIRST occurrence  → forward immediately, register in cache
// DUPLICATE within TTL window:
//   - accumulate attempt count + unique source IPs
//   - if count >= FLUSH_THRESHOLD  → flush summary NOW
//   - if time since last flush >= FLUSH_INTERVAL_MS → flush summary
//   - otherwise → drop silently (no downstream load)
// FLUSH = synthetic enriched alert carrying full burst stats
//         so AI investigation + Telegram see the brute-force picture
// ═══════════════════════════════════════════════════════

const DEDUP_WINDOW_MS    = 5  * 60 * 1000;  // 5-min suppression window
const FLUSH_INTERVAL_MS  = 60 * 1000;        // flush summary every 60 s max
const FLUSH_THRESHOLD    = 10;               // or immediately after 10 dupes

if (!global.SOC_DEDUP_CACHE) global.SOC_DEDUP_CACHE = {};
const cache = global.SOC_DEDUP_CACHE;
const now   = Date.now();

// Purge stale entries
for (const [key, entry] of Object.entries(cache)) {
  if (now - entry.first_seen > DEDUP_WINDOW_MS) delete cache[key];
}

const _e = JSON.parse(JSON.stringify($input.item.json._e));

// ── Fingerprint: rule + agent + /24 subnet + rule groups ──
const raw_src       = _e?.network?.src_ip || null;
const ip_bucket     = raw_src ? raw_src.replace(/\.(\d+)$/, '.0') : 'no-src';
const rule_id       = _e?.alert?.rule_id   || 'unknown';
const rule_desc     = _e?.alert?.rule_desc || 'unknown';
const agent         = _e?.host?.agent_name || 'unknown';
const groups        = JSON.stringify((_e?.alert?.rule_groups || []).sort());
const fingerprint   = `${rule_id}|${agent}|${ip_bucket}|${groups}`;

const entry = cache[fingerprint];

// ────────────────────────────────────────────────
// CASE A: FIRST OCCURRENCE — register + forward
// ────────────────────────────────────────────────
if (!entry) {
  cache[fingerprint] = {
    first_seen:    now,
    last_seen:     now,
    last_flush_at: now,
    count:         1,           // total attempts seen
    src_ips:       raw_src ? new Set([raw_src]) : new Set(),
    rule_id,
    rule_desc,
    agent,
    ip_bucket,
    fingerprint
  };

  _e._dedup = {
    suppressed:     false,
    is_first:       true,
    fingerprint,
    attempt_count:  1,
    unique_src_ips: raw_src ? [raw_src] : [],
    window_ms:      DEDUP_WINDOW_MS,
    reason:         'First occurrence — forwarded immediately'
  };

  return [{ json: { _e } }];
}

// ────────────────────────────────────────────────
// CASE B: DUPLICATE within TTL window — accumulate
// ────────────────────────────────────────────────
entry.count++;
entry.last_seen = now;
if (raw_src) entry.src_ips.add(raw_src);

const unique_ips    = [...entry.src_ips];
const since_flush   = now - entry.last_flush_at;
const should_flush  = entry.count >= FLUSH_THRESHOLD || since_flush >= FLUSH_INTERVAL_MS;

if (!should_flush) {
  // Silent drop — accumulating, not yet time to flush
  _e._dedup = {
    suppressed:     true,
    is_first:       false,
    fingerprint,
    attempt_count:  entry.count,
    unique_src_ips: unique_ips,
    window_ms:      DEDUP_WINDOW_MS,
    next_flush_in_ms: Math.max(0, FLUSH_INTERVAL_MS - since_flush),
    reason:         `Suppressed duplicate ${entry.count}: rule ${rule_id} on ${agent} — flush in ${Math.round((FLUSH_INTERVAL_MS - since_flush)/1000)}s or after ${FLUSH_THRESHOLD - entry.count} more hits`
  };
  return [];  // drop — no downstream processing
}

// ────────────────────────────────────────────────
// CASE C: FLUSH — synthesise a burst summary alert
// that carries full attack stats into investigation
// ────────────────────────────────────────────────
entry.last_flush_at = now;

// Determine attack pattern type from rule groups
const groupArr = JSON.parse(groups);
const isBrute  = groupArr.some(g => /brute.?force|authentication_failure|multiple_failed/i.test(g));
const isSpray  = unique_ips.length >= 3;  // 3+ distinct sources = spray
const attackPattern = isSpray  ? 'PASSWORD_SPRAY'
                    : isBrute  ? 'BRUTE_FORCE'
                    : 'REPEATED_ALERT_BURST';

// Burst duration in seconds
const burst_duration_s = Math.round((now - entry.first_seen) / 1000);
const rate_per_min     = burst_duration_s > 0
  ? Math.round((entry.count / burst_duration_s) * 60)
  : entry.count;

// Build synthetic enriched _e with burst metadata injected into alert
const burst_e = JSON.parse(JSON.stringify(_e));

// Override alert fields so AI sees the full burst picture
burst_e.alert.rule_desc = `[${attackPattern}] ${rule_desc} — ${entry.count} attempts in ${burst_duration_s}s from ${unique_ips.length} source IP(s)`;
burst_e.alert.fired_times = entry.count;
burst_e.alert.full_log = [
  `BURST SUMMARY | Pattern: ${attackPattern}`,
  `Target Agent  : ${agent}`,
  `Rule          : ${rule_id} — ${rule_desc}`,
  `Total Attempts: ${entry.count}`,
  `Rate          : ~${rate_per_min} attempts/min`,
  `Duration      : ${burst_duration_s}s`,
  `Unique Sources: ${unique_ips.length}`,
  `Source IPs    : ${unique_ips.join(', ')}`,
  `Window Start  : ${new Date(entry.first_seen).toISOString()}`,
  `Flush Time    : ${new Date(now).toISOString()}`
].join('\n');

// Override src_ip with the most active source (first seen)
burst_e.network.src_ip = unique_ips[0] || raw_src;

// Stamp dedup metadata
burst_e._dedup = {
  suppressed:     false,
  is_first:       false,
  is_burst_flush: true,
  attack_pattern: attackPattern,
  fingerprint,
  attempt_count:  entry.count,
  unique_src_ips: unique_ips,
  burst_duration_s,
  rate_per_min,
  window_ms:      DEDUP_WINDOW_MS,
  flush_trigger:  entry.count >= FLUSH_THRESHOLD ? 'threshold' : 'interval',
  reason:         `Burst flush: ${attackPattern} — ${entry.count} attempts, ${unique_ips.length} sources, ${rate_per_min}/min`
};

// New alert_id to distinguish the burst summary from original
burst_e.alert_id = `burst-${rule_id}-${agent.replace(/[^a-z0-9]/gi,'-')}-${now}`;

return [{ json: { _e: burst_e } }];

// ═══════════════════════════════════════════════════════════════════════
// SOC E2E LIFECYCLE BENCHMARK v4.1 — No fs, n8n native file pipeline
// Session stats computed from global (in-memory, reset on restart)
// Persistent write handled by downstream Convert to File + ReadWriteFile
// ═══════════════════════════════════════════════════════════════════════

const now   = Date.now();
const item  = $input.item.json;
const _e    = item?._e    || {};
const AUDIT = item?.AUDIT || {};

// ── CONFIG ───────────────────────────────────────────────────────────────
const CFG = {
  cost_per_token_usd:  0.0000006,  // ← single configurable rate
  outlier_threshold_s: 120,        // ai_pipeline > this = QUEUED_ANOMALY
  max_global_records:  1000        // rolling in-memory cap
};

// ── 1. TIMESTAMP PIPELINE ────────────────────────────────────────────────
const toMs = (v) => v ? new Date(v).getTime() : null;

const ms = {
  origin: toMs(_e.alert?.timestamp        || AUDIT.alert?.timestamp),
  ingest: toMs(_e.timeline?.received_at   || AUDIT.timeline?.received_at) || now,
  ti_end: toMs(_e.timeline?.ti_completed_at || AUDIT.timeline?.ti_completed_at),
  ai_end: toMs(_e.timeline?.ai_completed_at || AUDIT.timeline?.ai_completed_at),
  egress: now
};

// ── 2. LATENCY CHAIN ─────────────────────────────────────────────────────
const net_lag_ms     = ms.origin ? Math.max(0, ms.ingest - ms.origin) : null;
const ti_proc_ms     = (ms.ti_end && ms.ingest) ? Math.max(0, ms.ti_end - ms.ingest) : null;
const ai_pipeline_ms = (ms.ai_end && ms.ti_end) ? Math.max(0, ms.ai_end - ms.ti_end) : null;
const soar_proc_ms   = Math.max(0, ms.egress - ms.ingest);
const e2e_total_ms   = ms.origin ? Math.max(0, ms.egress - ms.origin) : soar_proc_ms;

// ── 3. OUTLIER DETECTION ─────────────────────────────────────────────────
const ai_pipeline_s = ai_pipeline_ms !== null ? +(ai_pipeline_ms / 1000).toFixed(3) : null;
const anomaly_flag  = (ai_pipeline_s !== null && ai_pipeline_s > CFG.outlier_threshold_s)
  ? 'QUEUED_ANOMALY' : 'NORMAL';

// ── 4. INFORMATION DENSITY ───────────────────────────────────────────────
const raw_size      = JSON.stringify(item).length;
const summary_text  = item?.summary || item?.text || '';
const summary_size  = summary_text.length;
const compression_ratio = summary_size > 0
  ? parseFloat((raw_size / summary_size).toFixed(2))
  : null;

// ── 5. COST ──────────────────────────────────────────────────────────────
const tokens_used = AUDIT.tokens_used || 0;
const cost_usd    = parseFloat((tokens_used * CFG.cost_per_token_usd).toFixed(8));

// ── 6. BUILD RECORD ──────────────────────────────────────────────────────
const record = {
  id:          `BM-${now}`,
  alert_id:    _e.alert_id || AUDIT.alert_id || 'unknown',
  session_ts:  new Date(now).toISOString(),

  classification: {
    rule_id:       _e.alert?.rule_id           || AUDIT.alert?.rule_id       || null,
    rule_level:    _e.alert?.rule_level         || AUDIT.alert?.rule_level    || null,
    severity_tier: _e.severity_tier             || AUDIT.response?.severity_tier || null,
    verdict:       AUDIT.analysis?.verdict      || 'PENDING',
    confidence:    AUDIT.analysis?.confidence   || null,
    attack_type:   AUDIT.analysis?.attack_type  || null,
    risk_score:    AUDIT.analysis?.risk_score   ?? null,
    is_malicious:  _e.is_malicious              ?? AUDIT.response?.is_malicious ?? null
  },

  timing: {
    net_ingest_lag_s:  net_lag_ms    !== null ? +(net_lag_ms    / 1000).toFixed(3) : null,
    ti_processing_s:   ti_proc_ms    !== null ? +(ti_proc_ms    / 1000).toFixed(3) : null,
    ai_pipeline_s:     ai_pipeline_s,
    soar_internal_s:   +(soar_proc_ms  / 1000).toFixed(3),
    e2e_total_s:       +(e2e_total_ms  / 1000).toFixed(3),
    anomaly_flag:      anomaly_flag
  },

  ai_perf: {
    provider:    AUDIT.ai_provider || null,
    model:       AUDIT.ai_model    || null,
    tokens_used: tokens_used,
    cost_usd:    cost_usd,
    response_ms: AUDIT.response_ms || null
  },

  ti_coverage: {
    engines_total:   _e.threat_intel?.summary?.engines_total   || 0,
    engines_ok:      _e.threat_intel?.summary?.engines_ok      || 0,
    engines_skipped: _e.threat_intel?.summary?.engines_skipped || 0,
    engines_error:   _e.threat_intel?.summary?.engines_error   || 0,
    ti_verdict:      _e.threat_intel?.summary?.verdict         || AUDIT.threat_intel?.verdict || null,
    ti_score:        _e.threat_intel?.summary?.score           ?? null,
    ioc_count:       (_e.iocs?.ips?.length     || 0) +
                     (_e.iocs?.domains?.length || 0) +
                     (_e.iocs?.hashes?.length  || 0) +
                     (_e.iocs?.urls?.length    || 0)
  },

  dedup: {
    is_first:       _e._dedup?.is_first      ?? true,
    attempt_count:  _e._dedup?.attempt_count || 1,
    suppressed:     _e._dedup?.suppressed    ?? false,
    attack_pattern: _e._dedup?.attack_pattern || null
  },

  density: {
    raw_payload_bytes: raw_size,
    summary_bytes:     summary_size || null,
    compression_ratio: compression_ratio
  }
};

// ── 7. IN-MEMORY SESSION STATS (global — resets on container restart) ────
if (!global.BENCH_RECORDS) global.BENCH_RECORDS = [];
global.BENCH_RECORDS.push(record);
if (global.BENCH_RECORDS.length > CFG.max_global_records) {
  global.BENCH_RECORDS.shift();
}

const normalRecs = global.BENCH_RECORDS.filter(r => r.timing.anomaly_flag === 'NORMAL');

const statOf = (field) => {
  const vals = normalRecs
    .map(r => r.timing[field])
    .filter(v => v !== null && v !== undefined && !isNaN(v));
  if (vals.length === 0) return { mean: null, stddev: null, p50: null, p95: null, p99: null, n: 0 };
  const sorted = [...vals].sort((a, b) => a - b);
  const mean   = vals.reduce((s, v) => s + v, 0) / vals.length;
  const stddev = Math.sqrt(vals.reduce((s, v) => s + (v - mean) ** 2, 0) / vals.length);
  const pct    = (p) => sorted[Math.min(Math.floor(p * sorted.length), sorted.length - 1)];
  return {
    mean:   +mean.toFixed(3),
    stddev: +stddev.toFixed(3),
    p50:    +pct(0.50).toFixed(3),
    p95:    +pct(0.95).toFixed(3),
    p99:    +pct(0.99).toFixed(3),
    n:      vals.length
  };
};

const verdictCounts = global.BENCH_RECORDS.reduce((acc, r) => {
  const v = r.classification.verdict || 'UNKNOWN';
  acc[v] = (acc[v] || 0) + 1;
  return acc;
}, {});

const anomalyCount = global.BENCH_RECORDS.filter(r => r.timing.anomaly_flag === 'QUEUED_ANOMALY').length;
const totalCost    = global.BENCH_RECORDS.reduce((s, r) => s + (r.ai_perf.cost_usd || 0), 0);
const totalTokens  = global.BENCH_RECORDS.reduce((s, r) => s + (r.ai_perf.tokens_used || 0), 0);

const session_stats = {
  total_alerts:    global.BENCH_RECORDS.length,
  normal_alerts:   normalRecs.length,
  anomaly_alerts:  anomalyCount,
  anomaly_rate_pct: global.BENCH_RECORDS.length > 0
    ? +((anomalyCount / global.BENCH_RECORDS.length) * 100).toFixed(2) : 0,
  latency_stats: {
    net_ingest_lag_s: statOf('net_ingest_lag_s'),
    ti_processing_s:  statOf('ti_processing_s'),
    ai_pipeline_s:    statOf('ai_pipeline_s'),
    soar_internal_s:  statOf('soar_internal_s'),
    e2e_total_s:      statOf('e2e_total_s')
  },
  verdict_distribution: verdictCounts,
  false_positive_rate_pct: (() => {
    const total = global.BENCH_RECORDS.length;
    const fp    = verdictCounts['FALSE_POSITIVE'] || 0;
    return total > 0 ? +((fp / total) * 100).toFixed(2) : null;
  })(),
  cost_summary: {
    total_tokens_used:  totalTokens,
    total_cost_usd:     +totalCost.toFixed(6),
    avg_cost_per_alert: global.BENCH_RECORDS.length > 0
      ? +(totalCost / global.BENCH_RECORDS.length).toFixed(8) : 0
  },
  ti_hit_rate_pct: (() => {
    const hits = global.BENCH_RECORDS.filter(r => (r.ti_coverage.ioc_count || 0) > 0).length;
    return global.BENCH_RECORDS.length > 0
      ? +((hits / global.BENCH_RECORDS.length) * 100).toFixed(2) : null;
  })(),
  computed_at: new Date(now).toISOString()
};

// ── 8. CSV ROW STRING (passed to Convert to File node) ───────────────────
const CSV_HEADER = [
  'id','alert_id','session_ts',
  'rule_id','rule_level','severity_tier','verdict','confidence','risk_score','is_malicious',
  'net_ingest_lag_s','ti_processing_s','ai_pipeline_s','soar_internal_s','e2e_total_s','anomaly_flag',
  'ai_provider','ai_model','tokens_used','cost_usd','response_ms',
  'engines_total','engines_ok','engines_skipped','engines_error','ti_verdict','ti_score','ioc_count',
  'is_first','attempt_count','suppressed',
  'raw_payload_bytes','summary_bytes','compression_ratio'
].join(',');

const esc = (v) => {
  if (v === null || v === undefined) return '';
  const s = String(v);
  return s.includes(',') || s.includes('"') || s.includes('\n')
    ? `"${s.replace(/"/g, '""')}"` : s;
};

const csvRow = [
  record.id, record.alert_id, record.session_ts,
  record.classification.rule_id, record.classification.rule_level,
  record.classification.severity_tier, record.classification.verdict,
  record.classification.confidence, record.classification.risk_score,
  record.classification.is_malicious,
  record.timing.net_ingest_lag_s, record.timing.ti_processing_s,
  record.timing.ai_pipeline_s, record.timing.soar_internal_s,
  record.timing.e2e_total_s, record.timing.anomaly_flag,
  record.ai_perf.provider, record.ai_perf.model,
  record.ai_perf.tokens_used, record.ai_perf.cost_usd, record.ai_perf.response_ms,
  record.ti_coverage.engines_total, record.ti_coverage.engines_ok,
  record.ti_coverage.engines_skipped, record.ti_coverage.engines_error,
  record.ti_coverage.ti_verdict, record.ti_coverage.ti_score, record.ti_coverage.ioc_count,
  record.dedup.is_first, record.dedup.attempt_count, record.dedup.suppressed,
  record.density.raw_payload_bytes, record.density.summary_bytes,
  record.density.compression_ratio
].map(esc).join(',');

// NOTE: Header is only prepended when this is the very first record
const csvText = global.BENCH_RECORDS.length === 1
  ? `${CSV_HEADER}\n${csvRow}`
  : csvRow;

return [{
  json: {
    benchmark_record: record,
    session_stats,
    csvText,          // → fed into Convert to File node
    telegram_summary:
      `📊 *Benchmark*\n` +
      `E2E: ${record.timing.e2e_total_s}s | AI: ${record.timing.ai_pipeline_s}s ` +
      `${anomaly_flag === 'QUEUED_ANOMALY' ? '⚠️ ANOMALY' : '✅'}\n` +
      `Verdict: ${record.classification.verdict} | Risk: ${record.classification.risk_score}\n` +
      `Session n=${session_stats.total_alerts} | FP: ${session_stats.false_positive_rate_pct}% | ` +
      `Cost: $${session_stats.cost_summary.total_cost_usd}`
  }
}];

// ═══════════════════════════════════════════════════════════════
// PARSE AI + BUILD AUDIT — SOC v2
// Parses Groq response + restores _e + builds AUDIT record
// ═══════════════════════════════════════════════════════════════
const _e = JSON.parse(JSON.stringify($('C — Aggregate TI').first().json._e));

let raw = '{}';
try { raw = $input.item.json?.choices?.[0]?.message?.content || '{}'; } catch { raw = '{}'; }
raw = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();

let ai = {};
try {
  ai = JSON.parse(raw);
} catch {
  ai = {
    alert_summary: `[PARSE ERROR] ${_e.alert.rule_desc}`,
    attack_type: null,
    alert_verdict: 'NEEDS_INVESTIGATION',
    confidence: 'LOW',
    incident_severity: 'HIGH',
    risk_score: 50,
    mitre_attack: { tactics:[], techniques:[], sub_techniques:[] },
    ioc_analysis: { malicious_ips:[], malicious_domains:[], malicious_hashes:[], suspicious_urls:[], ioc_verdict:'unknown' },
    false_positive_indicators: [],
    analysis: `AI parse failed. TI verdict: ${_e.threat_intel?.summary?.verdict}. Score: ${_e.threat_intel?.summary?.score}. Manual review required.`,
    investigation_timeline: ['Step 1 — Manual triage required','Step 2 — Review Groq execution log'],
    affected_assets: [_e.host.agent_name],
    recommended_actions: ['P0 — Manual triage — AI parse failed'],
    detection_improvements: [],
    threat_actor_profile: null,
    zero_day_indicators: [],
    analyst_notes: `Raw Groq output (first 300 chars): ${raw.slice(0,300)}`
  };
}

_e.ai_analysis = ai;
_e.timeline.ai_completed_at = new Date().toISOString();

const lvl = _e.alert.rule_level;
let tier = 'low';
if      (lvl >= 12) tier = 'critical';
else if (lvl >= 9)  tier = 'high';
else if (lvl >= 6)  tier = 'medium';
if (ai.incident_severity === 'CRITICAL' && tier !== 'critical') tier = 'critical';
if (ai.incident_severity === 'HIGH' && tier === 'low') tier = 'medium';

_e.severity_tier = tier;
_e.is_malicious = _e.threat_intel?.summary?.verdict === 'malicious' || ai.alert_verdict === 'TRUE_POSITIVE';

const AUDIT = {
  alert_id:  _e.alert_id,
  pipeline:  _e.pipeline,
  host: { ..._e.host },
  alert: {
    rule_id:    _e.alert.rule_id,
    rule_desc:  _e.alert.rule_desc,
    rule_level: _e.alert.rule_level,
    timestamp:  _e.alert.timestamp,
    mitre:      _e.alert.mitre,
    cmdline:    _e.alert.cmdline
  },
  iocs: { ..._e.iocs },
  threat_intel: {
    verdict:    _e.threat_intel.summary?.verdict,
    score:      _e.threat_intel.summary?.score,
    flagged:    _e.threat_intel.summary?.flagged,
    engines:    _e.threat_intel.engines,
    ip_rep:     _e.threat_intel.ip_rep,
    domain_rep: _e.threat_intel.domain_rep,
    hash_rep:   _e.threat_intel.hash_rep
  },
  analysis: {
    verdict:       ai.alert_verdict,
    confidence:    ai.confidence,
    severity:      ai.incident_severity,
    risk_score:    ai.risk_score || 0,
    attack_type:   ai.attack_type,
    summary:       ai.alert_summary,
    detail:        ai.analysis,
    mitre_mapped:  ai.mitre_attack,
    ioc_verdict:   ai.ioc_analysis,
    timeline:      ai.investigation_timeline || [],
    assets:        ai.affected_assets || [],
    actions:       ai.recommended_actions || [],
    improvements:  ai.detection_improvements || [],
    fp_indicators: ai.false_positive_indicators || [],
    threat_actor:  ai.threat_actor_profile || null,
    zero_day:      ai.zero_day_indicators || [],
    analyst_notes: ai.analyst_notes || null
  },
  response: {
    severity_tier: tier,
    is_malicious:  _e.is_malicious
  },
  // After: response: { severity_tier: tier, is_malicious: _e.is_malicious },
dedup: {
  is_burst_flush:  _e._dedup?.is_burst_flush  ?? false,
  is_first:        _e._dedup?.is_first         ?? true,
  attack_pattern:  _e._dedup?.attack_pattern   || null,
  attempt_count:   _e._dedup?.attempt_count    || 1,
  unique_src_ips:  _e._dedup?.unique_src_ips   || [],
  burst_duration_s:_e._dedup?.burst_duration_s || null,
  rate_per_min:    _e._dedup?.rate_per_min     || null,
  flush_trigger:   _e._dedup?.flush_trigger    || null,
  reason:          _e._dedup?.reason           || null
},
  ai_provider: 'Groq',
  ai_model:    $input.item.json?.model || 'llama-3.3-70b-versatile',
  tokens_used: $input.item.json?.usage?.total_tokens || 0,
  response_ms: Math.round(($input.item.json?.usage?.total_time || 0) * 1000),
  timeline: {
    ..._e.timeline,
    total_ms: Date.now() - new Date(_e.timeline.received_at).getTime()
  }
};

return [{ json: { _e, AUDIT } }];
